  1→import { AIEngine, ENGINE_WEIGHTS, ENGINE_PROFILES, getScoreLevel } from '../config/engine-weights';
  2→
  3→/**
  4→ * Résultat d'un critère individuel issu de l'analyse AEO existante.
  5→ */
  6→export interface CriterionResult {
  7→  id: string;           // ex: 'AEO-TECH-01', 'AEO-DATA-03'
  8→  passed: boolean;      // critère validé ou non
  9→  score: number;        // score brut du critère (0 ou 1 dans le système actuel)
 10→  maxPoints: number;    // points max possibles (1 dans le système actuel)
 11→  category: string;     // catégorie parente (ex: 'technical')
 12→}
 13→
 14→/**
 15→ * Score calculé pour un moteur IA spécifique
 16→ */
 17→export interface EngineScore {
 18→  engineId: AIEngine;
 19→  engineName: string;
 20→  engineIcon: string;
 21→  engineColor: string;
 22→  bgClass: string;
 23→  textClass: string;
 24→  score: number;          // 0-100
 25→  level: { label: string; emoji: string; labelEn: string };
 26→  description: string;
 27→  topStrengths: string[];
 28→  topWeaknesses: string[];
 29→}
 30→
 31→/**
 32→ * Calcule les sous-scores par moteur à partir des résultats d'analyse existants.
 33→ *
 34→ * ALGORITHME :
 35→ * 1. Pour chaque moteur, on prend tous les critères analysés
 36→ * 2. On multiplie le score de chaque critère par le coefficient du moteur
 37→ * 3. On divise par le total des points max pondérés
 38→ * 4. On normalise sur 100
 39→ *
 40→ * Aucun appel API — calcul purement mathématique.
 41→ */
 42→export function calculateEngineScores(criteriaResults: CriterionResult[]): EngineScore[] {
 43→  const engines: AIEngine[] = ['chatgpt', 'perplexity', 'gemini'];
 44→
 45→  return engines.map((engineId) => {
 46→    let weightedScore = 0;
 47→    let weightedMax = 0;
 48→    const strengths: Array<{ id: string; weight: number }> = [];
 49→    const weaknesses: Array<{ id: string; weight: number }> = [];
 50→
 51→    criteriaResults.forEach((criterion) => {
 52→      const weight = ENGINE_WEIGHTS[criterion.id]?.[engineId] ?? 1.0;
 53→      const criterionWeightedMax = criterion.maxPoints * weight;
 54→
 55→      weightedMax += criterionWeightedMax;
 56→
 57→      if (criterion.passed) {
 58→        weightedScore += criterion.score * weight;
 59→        if (weight >= 1.3) {
 60→          strengths.push({ id: criterion.id, weight });
 61→        }
 62→      } else {
 63→        if (weight >= 1.3) {
 64→          weaknesses.push({ id: criterion.id, weight });
 65→        }
 66→      }
 67→    });
 68→
 69→    const normalizedScore = weightedMax > 0
 70→      ? Math.round((weightedScore / weightedMax) * 100)
 71→      : 0;
 72→
 73→    const profile = ENGINE_PROFILES[engineId];
 74→    const level = getScoreLevel(normalizedScore);
 75→
 76→    strengths.sort((a, b) => b.weight - a.weight);
 77→    weaknesses.sort((a, b) => b.weight - a.weight);
 78→
 79→    return {
 80→      engineId,
 81→      engineName: profile.name,
 82→      engineIcon: profile.icon,
 83→      engineColor: profile.color,
 84→      bgClass: profile.bgClass,
 85→      textClass: profile.textClass,
 86→      score: normalizedScore,
 87→      level,
 88→      description: profile.description,
 89→      topStrengths: strengths.slice(0, 3).map(s => s.id),
 90→      topWeaknesses: weaknesses.slice(0, 3).map(w => w.id),
 91→    };
 92→  });
 93→}
 94→
 95→/**
 96→ * Calcule le score projeté si certaines recommandations sont implémentées.
 97→ *
 98→ * Prend les résultats actuels et simule le passage de certains critères à "passed".
 99→ * Retourne le nouveau score global + les nouveaux sous-scores par moteur.
100→ * Aucun appel API — calcul purement mathématique.
101→ */
102→export function calculateProjectedScores(
103→  currentResults: CriterionResult[],
104→  fixedCriteriaIds: string[]
105→): { globalScore: number; engineScores: EngineScore[] } {
106→
107→  // Clone les résultats et marque les critères fixés comme "passed"
108→  const projectedResults = currentResults.map((criterion) => {
109→    if (fixedCriteriaIds.includes(criterion.id)) {
110→      return { ...criterion, passed: true, score: criterion.maxPoints };
111→    }
112→    return criterion;
113→  });
114→
115→  // Recalcule le score global (simple average of passed / total)
116→  const totalScore = projectedResults.reduce((sum, c) => sum + c.score, 0);
117→  const totalMax = projectedResults.reduce((sum, c) => sum + c.maxPoints, 0);
118→  const globalScore = totalMax > 0 ? Math.round((totalScore / totalMax) * 100) : 0;
119→
120→  // Recalcule les sous-scores par moteur
121→  const engineScores = calculateEngineScores(projectedResults);
122→
123→  return { globalScore, engineScores };
124→}
125→
126→/**
127→ * Retourne les IDs des moteurs les plus impactés par un critère donné.
128→ * Utile pour afficher les badges moteurs sur chaque recommandation.
129→ */
130→export function getMostImpactedEngines(criterionId: string): Array<{ engineId: AIEngine; weight: number }> {
131→  const weights = ENGINE_WEIGHTS[criterionId];
132→  if (!weights) return [];
133→
134→  const engines: AIEngine[] = ['chatgpt', 'perplexity', 'gemini'];
135→  return engines
136→    .map(id => ({ engineId: id, weight: weights[id] ?? 1.0 }))
137→    .filter(e => e.weight >= 1.3)
138→    .sort((a, b) => b.weight - a.weight);
139→}
