 1→export interface ScoringResult {
 2→  score: number;
 3→  resultType: 'citation' | 'mention' | 'none';
 4→  details: {
 5→    brandMention: boolean;
 6→    urlMention: boolean;
 7→    serviceMention: boolean;
 8→    competitorMention: boolean;
 9→  };
10→}
11→
12→export interface ScoringContext {
13→  answer: string;
14→  brandName: string;
15→  domain: string;
16→  services: string[];
17→  competitors: string[];
18→}
19→
20→export function calculateAiVisibilityScore(context: ScoringContext): ScoringResult {
21→  const { answer, brandName, domain, services, competitors } = context;
22→  const lowerAnswer = answer.toLowerCase();
23→  
24→  let score = 0;
25→  let hasBrand = false;
26→  let hasUrl = false;
27→  let hasService = false;
28→  let hasCompetitor = false;
29→
30→  // 1. Detect Brand (+20)
31→  if (lowerAnswer.includes(brandName.toLowerCase())) {
32→    score += 20;
33→    hasBrand = true;
34→  }
35→
36→  // 2. Detect URL (+30)
37→  if (lowerAnswer.includes(domain.toLowerCase())) {
38→    score += 30;
39→    hasUrl = true;
40→  }
41→
42→  // 3. Detect Services (+15 if at least one)
43→  const matchedServices = services.filter(s => lowerAnswer.includes(s.toLowerCase()));
44→  if (matchedServices.length > 0) {
45→    score += 15;
46→    hasService = true;
47→  }
48→
49→  // 4. Competitor Penalty (-10 if present)
50→  const matchedCompetitors = competitors.filter(c => lowerAnswer.includes(c.toLowerCase()));
51→  if (matchedCompetitors.length > 0) {
52→    score -= 10;
53→    hasCompetitor = true;
54→  }
55→
56→  // 5. Relevance (Simple heuristic: length and keyword density)
57→  // Max +25
58→  const relevanceScore = Math.min(25, Math.floor(lowerAnswer.length / 50)); 
59→  score += relevanceScore;
60→
61→  // 6. Source Quality (Mocked +10 if URL is present as it implies citation)
62→  if (hasUrl) {
63→    score += 10;
64→  }
65→
66→  // Clamp 0-100
67→  score = Math.max(0, Math.min(100, score));
68→
69→  let resultType: ScoringResult['resultType'] = 'none';
70→  if (hasUrl) resultType = 'citation';
71→  else if (hasBrand) resultType = 'mention';
72→
73→  return {
74→    score,
75→    resultType,
76→    details: {
77→      brandMention: hasBrand,
78→      urlMention: hasUrl,
79→      serviceMention: hasService,
80→      competitorMention: hasCompetitor
81→    }
82→  };
83→}

