 1→import { AnalysisResult } from '../types';
 2→import { CRITERIA_REPOSITORY } from '../services/criteria';
 3→import { CriterionResult } from './engine-score-calculator';
 4→
 5→/**
 6→ * Mappe les résultats d'analyse existants vers CriterionResult[].
 7→ *
 8→ * Le système actuel stocke les résultats par catégorie avec des items
 9→ * contenant status + message (nom du critère). On reconstruit les IDs
10→ * en croisant avec CRITERIA_REPOSITORY.
11→ */
12→export function mapAnalysisResults(data: AnalysisResult): CriterionResult[] {
13→  const results: CriterionResult[] = [];
14→
15→  // Index criteria by category_id for fast lookup
16→  const criteriaByCategory: Record<string, typeof CRITERIA_REPOSITORY> = {};
17→  CRITERIA_REPOSITORY.forEach((crit) => {
18→    if (!criteriaByCategory[crit.category_id]) {
19→      criteriaByCategory[crit.category_id] = [];
20→    }
21→    criteriaByCategory[crit.category_id].push(crit);
22→  });
23→
24→  // Iterate over each category in the analysis results
25→  Object.entries(data.categories).forEach(([categoryId, categoryScore]) => {
26→    const categoryCriteria = criteriaByCategory[categoryId] || [];
27→
28→    categoryScore.items.forEach((item, index) => {
29→      // Match by index position (criteria are in the same order as CRITERIA_REPOSITORY)
30→      const criterion = categoryCriteria[index];
31→      if (!criterion) return;
32→
33→      const passed = item.status === 'success';
34→
35→      results.push({
36→        id: criterion.id,
37→        passed,
38→        score: passed ? 1 : 0,
39→        maxPoints: 1,
40→        category: categoryId,
41→      });
42→    });
43→  });
44→
45→  return results;
46→}
